return [{json: {
  baseUrl: 'https://jira.navio.auto',
  token: 'replace_with_real_token',
  updateTemplate: 'rest/tests/1.0/testresult/{test_result_id}',
  updateMethod: 'PUT',
  statusField: 'testResultStatusId',
  commentField: 'comment',
  maxAttempts: 5
}}];

return items.map((item) => {
  const row = item.json;
  const payload = row.payload_json || {};
  return {
    json: {
      queue_id: String(row.queue_id),
      test_result_id: String(row.test_result_id),
      desired_status_id: payload.desired_status_id,
      desired_comment: payload.desired_comment || '',
      attempt_count: Number(row.attempt_count || 0),
      operation_hash: String(row.operation_hash || '')
    }
  };
});

const cfg = $items('Build_Config', 0, 0)[0].json;
return items.map((item) => {
  const row = item.json;
  const endpoint = cfg.updateTemplate.replace('{test_result_id}', String(row.test_result_id));
  return {
    json: {
      ...row,
      request_url: `${cfg.baseUrl}/${endpoint}`,
      request_method: cfg.updateMethod,
      request_body: {
        [cfg.statusField]: row.desired_status_id,
        [cfg.commentField]: row.desired_comment || ''
      },
      max_attempts: cfg.maxAttempts
    }
  };
});

return items.map((item) => {
  const j = item.json || {};
  const err = j.error;
  const code = Number(
    j.statusCode ??
    (err && err.status) ??
    (err && err.statusCode) ??
    0
  );
  const ok = !err && code >= 200 && code < 300;
  return { json: { ...j, __http_ok: ok, __http_status: code } };
});

return items.map((item) => ({json: {
  ...item.json,
  queue_status: 'done',
  sync_state: 'done',
  audit_success: true
}}));

return items.map((item) => {
  const row = item.json;
  const attempts = Number(row.attempt_count || 0) + 1;
  const retryDelayMin = Math.min(8, Math.pow(2, Math.max(0, attempts - 1)));
  const nextRetry = new Date(Date.now() + retryDelayMin * 60000).toISOString();
  const dead = attempts >= Number(row.max_attempts || 5);
  return {json: {
    ...row,
    attempt_count: attempts,
    queue_status: dead ? 'dead_letter' : 'failed',
    sync_state: dead ? 'dead_letter' : 'failed',
    next_retry_at: dead ? null : nextRetry,
    audit_success: false
  }};
});

const esc = (value) => {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
};

const sourceItems = $items('Build_Request', 0, 0);

return items.map((item, idx) => {
  const row = item.json || {};
  const src = (sourceItems[idx] && sourceItems[idx].json) ? sourceItems[idx].json : {};

  const queueId = row.queue_id ?? src.queue_id ?? null;
  const testResultId = row.test_result_id ?? src.test_result_id ?? null;
  const requestMethod = row.request_method ?? src.request_method ?? '';
  const requestUrl = row.request_url ?? src.request_url ?? '';
  const requestBody = row.request_body ?? src.request_body ?? {};

  const queueStatus = row.queue_status || 'failed';
  const syncState = row.sync_state || 'failed';
  const attemptCount = Number(row.attempt_count ?? src.attempt_count ?? 0);
  const nextRetry = row.next_retry_at ? `${esc(row.next_retry_at)}::timestamptz` : 'NULL';
  const errorText = row.audit_success ? 'NULL' : esc((row.error && row.error.message) ? row.error.message : 'request failed');
  const responseStatus = Number(row.__http_status || (row.error && row.error.status) || row.statusCode || 200);
  const responseBody = esc(row.error ? JSON.stringify(row.error) : JSON.stringify(row));

  if (!queueId || !testResultId) {
    throw new Error(`Missing queue linkage fields: queue_id=${queueId}, test_result_id=${testResultId}`);
  }

  const sql = `
    UPDATE sync_queue
    SET status = ${esc(queueStatus)},
        attempt_count = ${attemptCount},
        next_retry_at = ${nextRetry},
        last_error = ${errorText},
        updated_at = NOW()
    WHERE id::text = ${esc(queueId)};

    UPDATE test_results
    SET sync_state = ${esc(syncState)},
        sync_error = ${errorText},
        last_synced_status_name = CASE WHEN ${esc(syncState)} = 'done' THEN desired_status_name ELSE last_synced_status_name END,
        last_synced_comment = CASE WHEN ${esc(syncState)} = 'done' THEN desired_comment ELSE last_synced_comment END,
        updated_at = NOW()
    WHERE test_result_id = ${esc(testResultId)};

    INSERT INTO sync_audit (
      queue_id,
      test_result_id,
      request_method,
      request_url,
      request_body_json,
      response_status,
      response_body,
      success,
      executed_at
    ) VALUES (
      ${esc(queueId)}::uuid,
      ${esc(testResultId)},
      ${esc(requestMethod)},
      ${esc(requestUrl)},
      ${esc(JSON.stringify(requestBody))}::jsonb,
      ${responseStatus},
      ${responseBody},
      ${row.audit_success ? 'true' : 'false'},
      NOW()
    );
  `;

  return { json: { ...row, queue_id: queueId, test_result_id: testResultId, sql_query: sql } };
});
